property.value:
={{
(() => {
  // Read birthday Unix timestamp (seconds) from current item
  const birthdayTs = $json.fieldBirthday;

  // If birthday is missing / null / empty → return empty string
  if (!birthdayTs) {
    return "";
  }

  // Convert Unix timestamp (seconds) → milliseconds
  const date = new Date(birthdayTs * 1000);

  // Format as YYYY-MM-DD using a locale that enforces this format
  // and apply Europe/Berlin timezone (handles CET / CEST automatically)
  return date.toLocaleDateString('en-CA', {
    timeZone: 'Europe/Berlin',
  });
})()
}}

