dataFields.fieldValue:
={{
  (() => {
    // Read birthday from the custom field
    // Expected format: YYYY-MM-DD
    const bday =
      $('Changes in Pipedrive1').item.json.data.custom_fields["95cac42f721633965550204f2604728aad5844bf"]?.value;

    // If the birthday does not exist, return null
    // → n8n will treat this as an empty value
    if (!bday) {
      return "";
    }
    // Convert birthday to a Unix timestamp (seconds)
    // "T00:00:00Z" forces UTC midnight to avoid timezone day shifts
    return Math.floor(
      Date.parse(bday + "T00:00:00Z") / 1000
    );
  })()
}}

conditions.leftValue:
={{
(() => {
  // Read label IDs from "Changes in Pipedrive"
  // Can be either:
  // - string like "14,27"
  // - array like [14, 27]
  const raw = $('Changes in Pipedrive1').item.json.data.label_ids ?? [];

  // Normalize to array of numbers
  const labelIds = Array.isArray(raw)
    ? raw.map(Number)
    : String(raw)
        .split(',')
        .map(s => Number(s.trim()))
        .filter(n => !Number.isNaN(n));

  // TRUE if label 14 is present
  return labelIds.includes(14);
})()
}}

